public int centeredAverage(int[] nums)
{
   int sum = 0;
   int minimum = nums[0];
   int maximum = nums[0];
   for (int i = 0; i < nums.length; i++)
   {
       sum = sum + nums[i];
       //takes the sum of all the numbers in the array
       minimum = Math.min(minimum, nums[i]);
       maximum = Math.max(maximum, nums[i]);
       //compares the current minimum with a new number from the array
   }
   return (sum - minimum - maximum) / (nums.length - 2);
   //the int division used to produce the final average
}

