public boolean evenlySpaced(int a, int b, int c)
{
    /**int[] arrInOrder = new int[3];
    arrInOrder[0] = a;
    arrInOrder[1] = b;
    arrInOrder[2] = c;
    Arrays.sort(arrInOrder, 0, 3); */
    int small;
    int med, big;
    if ((a > b) && (a > c)) // if a is the biggest
   {
        big = a;
		if (b > c)
        {
            med = b;
            small = c;
        }
       else
       {
        	med = c;
           small = b;
       }  
   }
    else if ((b > a) && (b >c)) // if b is the biggest
    {
                big = b;
		if (a > c)
        {
            med = a;
            small = c;
        }
       else
       {
        	med = c;
           small = a;
       }  
    }
    else if ((c > a) && (c > b)) // if c is the biggest
    {
                big = c;
		if (a > b)
        {
            med = a;
            small = b;
        }
       else
       {
        	med = b;
           small = a;
       }  
    }
    else if (a == b || a == c || b == c)
    {
        return false;
    }

    if (big - med == med - small)
    {
        return true;
    }
    else
        return false;
}

