public boolean evenlySpaced(int a, int b, int c)
{
    int temp;

    if (b < a) //when b lss than a
    {
        temp = b;
        b = a;
        a = temp;
    }

    if (c < b) //when c less than b
    {
        temp = c;
        c = b;
        b = temp;
    } 

    if (b < a) //when b less than a
    {
        temp = b;
        b = a;
        a = temp;
    }

    return a - b == b - c; //difference between a and b is equal to the difference b and c

}

